class Solution:
    def minimizeStringValue(self, s: str) -> str:
        chars = 'abcdefghijklmnopqrstuvwxyz'
        n = len(s)
        res = list(s)
        for i in range(n):
            if s[i] == '?':
                for c in chars:
                    res[i] = c
                    if all(s[j] == res[j] or s[j] == '?' for j in range(i)):
                        break
                else:
                    continue
                break
        return ''.join(res)
